"use client";
import * as React from "react";
import { createToastGroup, toastAnatomy, type ToastGroup, type ToastOptions } from "@tessera/core";
import { createStrictContext, useExternalState } from "../utils/hooks";
import { Portal } from "../utils/portal";
import { CloseIcon } from "../utils/icons";

const [ToastGroupProvider, useToastGroupContext] = createStrictContext<ToastGroup>("Toast");

export interface ToastProviderProps {
  /** Default auto-dismiss duration in ms. Default 5000. */
  duration?: number;
  /** Maximum simultaneously visible toasts. Default 5. */
  max?: number;
  children: React.ReactNode;
}

export function ToastProvider({ duration, max, children }: ToastProviderProps) {
  const [group] = React.useState(() => createToastGroup({ duration, max }));
  return (
    <ToastGroupProvider value={group}>
      {children}
      <Toaster group={group} />
    </ToastGroupProvider>
  );
}

/** Imperative toast API: `const toast = useToast(); toast({ title: "Saved" })`. */
export function useToast() {
  const group = useToastGroupContext();
  return React.useMemo(() => {
    const toast = (options: ToastOptions) => group.create(options);
    toast.dismiss = (id: string) => group.dismiss(id);
    toast.clear = () => group.clear();
    return toast;
  }, [group]);
}

function Toaster({ group }: { group: ToastGroup }) {
  const { toasts } = useExternalState(group);
  if (toasts.length === 0) return null;

  return (
    <Portal>
      <ol
        {...toastAnatomy.attrs("viewport")}
        aria-label="Notifications"
        onMouseEnter={() => group.pauseAll()}
        onMouseLeave={() => group.resumeAll()}
      >
        {toasts.map((toast) => (
          <li
            key={toast.id}
            {...toastAnatomy.attrs("root")}
            role="status"
            aria-live="polite"
            data-type={toast.type}
          >
            <div {...toastAnatomy.attrs("title")}>{toast.title}</div>
            {toast.description && (
              <div {...toastAnatomy.attrs("description")}>{toast.description}</div>
            )}
            <button
              type="button"
              {...toastAnatomy.attrs("close")}
              aria-label="Dismiss notification"
              onClick={() => group.dismiss(toast.id)}
            >
              <CloseIcon />
            </button>
          </li>
        ))}
      </ol>
    </Portal>
  );
}

@layer tessera.recipes {
  [data-scope="toast"][data-part="viewport"] {
    position: fixed;
    bottom: var(--ts-space-4);
    right: var(--ts-space-4);
    z-index: var(--ts-z-toast);
    display: flex;
    flex-direction: column;
    gap: var(--ts-space-2);
    width: 22rem;
    max-width: calc(100vw - var(--ts-space-8));
    margin: 0;
    padding: 0;
    list-style: none;
  }

  [data-scope="toast"][data-part="root"] {
    position: relative;
    display: flex;
    flex-direction: column;
    gap: var(--ts-space-1);
    background: var(--ts-bg-raised);
    color: var(--ts-fg-default);
    border: 1px solid var(--ts-border-muted);
    border-left: 3px solid var(--ts-accent-default);
    border-radius: var(--ts-radius-lg);
    box-shadow: var(--ts-shadow-md);
    padding: var(--ts-space-3) var(--ts-space-8) var(--ts-space-3) var(--ts-space-3);
    animation: tessera-toast-in var(--ts-duration-normal) var(--ts-easing-enter);
  }

  [data-scope="toast"][data-part="root"][data-type="success"] {
    border-left-color: var(--ts-success-default);
  }

  [data-scope="toast"][data-part="root"][data-type="warning"] {
    border-left-color: var(--ts-warning-default);
  }

  [data-scope="toast"][data-part="root"][data-type="danger"] {
    border-left-color: var(--ts-danger-default);
  }

  [data-scope="toast"][data-part="title"] {
    font-size: var(--ts-font-size-sm);
    font-weight: var(--ts-font-weight-semibold);
  }

  [data-scope="toast"][data-part="description"] {
    font-size: var(--ts-font-size-xs);
    color: var(--ts-fg-muted);
    line-height: var(--ts-font-leading-normal);
  }

  [data-scope="toast"][data-part="close"] {
    position: absolute;
    top: var(--ts-space-2);
    right: var(--ts-space-2);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 1.5rem;
    height: 1.5rem;
    border: none;
    border-radius: var(--ts-radius-sm);
    background: transparent;
    color: var(--ts-fg-muted);
    cursor: pointer;
  }

  [data-scope="toast"][data-part="close"]:hover {
    background: var(--ts-bg-subtle);
    color: var(--ts-fg-default);
  }

  @keyframes tessera-toast-in {
    from {
      opacity: 0;
      transform: translateX(1rem);
    }
  }
}
